    {
        GrindAudio.volume = Mathf.Lerp(GrindAudio.volume, targetVolume, lerpSpeed * Time.deltaTime);
    }

    public void RotateAround(Vector3 point, Vector3 axis, float angle)
    {
        rb.transform.RotateAround(point, axis, angle * Time.deltaTime);
    }

    public void Rotate(Vector3 axis, float angle, Space relativeTo)
