        rb.transform.rotation = Quaternion.Lerp(rb.transform.rotation, targetRotation, lerpSpeed * Time.deltaTime);
    }

    // Add the following method to start the grind
    public void StartGrind()
    {
        grindDetection.StartGrind();
    }

